package main

// Challenge 1.1 — CLI Calculator
//
// Build a command-line calculator that takes two numbers and an operator as arguments.
//
//   go run . 10 + 5    → 15
//   go run . 10 / 0    → error: division by zero
//   go run . 3.5 * 2   → 7
//
// Steps:
//   1. Read os.Args and validate the input (need exactly 3 args: num op num)
//   2. Parse the numbers using strconv.ParseFloat
//   3. Use a switch statement on the operator
//   4. Return errors using Go's (value, error) pattern — no exceptions here
//
// Key things to notice:
//   - Functions can return multiple values: func divide(a, b float64) (float64, error)
//   - Errors are just values: return 0, fmt.Errorf("division by zero")
//   - The caller always checks: result, err := calculate(...); if err != nil { ... }
import (
	"errors"
	"fmt"
	"os"
)

type Operator int

const (
	Addition = iota
	Substraction
	Multiplication
	Division
)

var operatorRune = map[Operator]rune{
	Addition:       '+',
	Substraction:   '-',
	Multiplication: '*',
	Division:       '/',
}

func (op rune) Operator() Operator {

}

func calculate(a, b float64, op rune) (float64, error) {

}

func add(a , b float64) float64 {
	return a + b
}

func sub(a , b float64) float64 {
	return a - b
}

func mult(a, b float64) float64 {
	return a * b
}

func div(a, b float64) (float64, error) {
	if b == 0.0 {
		return -1, errors.New("Divison by zero")
	}
	return a / b, nil
}

func main() {
	args := os.Args[1:]

	num1 := args[0]
	op := args[1]
	num2 := args[2]

	fmt.Println(num1)
	fmt.Println(op)
	fmt.Println(num2)
}

content.text:
There's a Go limitation here: `func (op rune) Operator()` won't compile because **you can't define methods on built-in types** like `rune` — only on types defined in your own package.

You have two clean options:

**Option 1 — Reverse the map (reuses what you have)**
```go
func ParseOperator(r rune) (Operator, error) {
    for op, ru := range operatorRune {
        if ru == r {
            return op, nil
        }
    }
    return -1, fmt.Errorf("unknown operator: %c", r)
}
```

**Option 2 — Switch statement (simpler, more readable)**
```go
func ParseOperator(r rune) (Operator, error) {
    switch r {
    case '+':
        return Addition, nil
    case '-':
        return Substraction, nil
    case '*':
        return Multiplication, nil
    case '/':
        return Division, nil
    default:
        return -1, fmt.Errorf("unknown operator: %c", r)
    }
}
```

I'd go with **Option 2** — it's clearer and avoids iterating the map.

Also a small tip: `op` from `os.Args` is a `string`, so you need to convert it to a rune first:
```go
op := rune(args[1][0])
operator, err := ParseOperator(op)
```

Looking at your current `calculate` signature:

```go
func calculate(a, b float64, op rune) (float64, error) {

}
```

You'd call `ParseOperator` to convert the rune, then switch on the result:

```go
func calculate(a, b float64, op rune) (float64, error) {
    operator, err := ParseOperator(op)
    if err != nil {
        return -1, err
    }

    switch operator {
    case Addition:
        return add(a, b), nil
    case Substraction:
        return sub(a, b), nil
    case Multiplication:
        return mult(a, b), nil
    case Division:
        return div(a, b)
    default:
        return -1, fmt.Errorf("unknown operator")
    }
}
```

Note that `div` already returns `(float64, error)` so you can return it directly without wrapping — `return div(a, b)` just forwards both values.

Good idea — you can add a second map that maps `Operator` to its function:

```go
var operatorFunc = map[Operator]func(float64, float64) (float64, error){
    Addition:       func(a, b float64) (float64, error) { return add(a, b), nil },
    Substraction:   func(a, b float64) (float64, error) { return sub(a, b), nil },
    Multiplication: func(a, b float64) (float64, error) { return mult(a, b), nil },
    Division:       div,
}
```

Then `calculate` becomes just:

```go
func calculate(a, b float64, op rune) (float64, error) {
    operator, err := ParseOperator(op)
    if err != nil {
        return -1, err
    }

    fn, ok := operatorFunc[operator]
    if !ok {
        return -1, fmt.Errorf("unknown operator")
    }

    return fn(a, b)
}
```

`div` can be referenced directly since it already has the right signature. `add`, `sub`, `mult` need a small wrapper because they return `float64`, not `(float64, error)`.

