package main

// Challenge 1.1 — CLI Calculator
//
// Build a command-line calculator that takes two numbers and an operator as arguments.
//
//   go run . 10 + 5    → 15
//   go run . 10 / 0    → error: division by zero
//   go run . 3.5 * 2   → 7
//
// Steps:
//   1. Read os.Args and validate the input (need exactly 3 args: num op num)
//   2. Parse the numbers using strconv.ParseFloat
//   3. Use a switch statement on the operator
//   4. Return errors using Go's (value, error) pattern — no exceptions here
//
// Key things to notice:
//   - Functions can return multiple values: func divide(a, b float64) (float64, error)
//   - Errors are just values: return 0, fmt.Errorf("division by zero")
//   - The caller always checks: result, err := calculate(...); if err != nil { ... }
import (
	"errors"
	"fmt"
	"os"
	"strconv"
)

type Operator int
type BinaryOp func(float64, float64)(float64, error)

const (
	Addition = iota
	Substraction
	Multiplication
	Division
)

var operatorFunc = map[Operator]BinaryOp{
	Addition:       add,
	Substraction:   sub,
	Multiplication: mult,
	Division:       div,
}

func ParseOperator(r rune) (Operator, error) {
	switch r {
	case '+': return Addition, nil
	case '-': return Substraction, nil
	case '*': return Multiplication, nil
	case '/': return Division, nil
	default: return -1, fmt.Errorf("unkonwn operator: %c", r)
	}
}

func calculate(a, b float64, op rune) (float64, error) {
	operator, err := ParseOperator(op)

	if err != nil {
		return -1, err
	}

	fn, ok := operatorFunc[operator]
	if !ok {
		return -1, fmt.Errorf("unknown operator")
	}
	return fn(a, b)
}

func add(a , b float64) (float64, error) {
	return a + b, nil
}

func sub(a , b float64) (float64, error) {
	return a - b, nil
}

func mult(a, b float64) (float64, error) {
	return a * b, nil
}

func div(a, b float64) (float64, error) {
	if b == 0.0 {
		return -1, errors.New("Divison by zero")
	}
	return a / b, nil
}

func main() {
	args := os.Args[1:]

	a, err := strconv.ParseFloat(args[0], 64)
	if err != nil {
		fmt.Printf("%s", err)
	}
	op := rune(args[1][0])
	b, err := strconv.ParseFloat(args[2], 64)
	if err != nil {
		fmt.Printf("%s", err)
	}


	result, err := calculate(a, b, op)
	if err != nil {
		fmt.Printf("%s", err)
	}
	fmt.Println(result)
}
